#include <stdio.h>

int main() {
    int s, v1, v2, t1, t2;
    scanf("%d %d %d %d %d", &s, &v1, &v2, &t1, &t2);
    int a = s * v1 + 2 * t1;
    int b = s * v2 + 2 * t2;
    if (a < b) {
        printf("First\n");
    }
    if (a > b) {
        printf("Second\n");
    }
    if (a == b) {
        printf("Friendship\n");
    }
    return 0;
}
